679: class FilterManager : public ScopeTrackedObject, Logger::Loggable<Logger::Id::http> {
680: public:
681:   FilterManager(FilterManagerCallbacks& filter_manager_callbacks, Event::Dispatcher& dispatcher,
682:                 OptRef<const Network::Connection> connection, uint64_t stream_id,
683:                 Buffer::BufferMemoryAccountSharedPtr account, bool proxy_100_continue,
684:                 uint64_t buffer_limit)
