686:         connection_(connection), stream_id_(stream_id), account_(std::move(account)),
687:         proxy_100_continue_(proxy_100_continue), buffer_limit_(buffer_limit) {}
688: 
689:   ~FilterManager() override {
690:     ASSERT(state_.destroyed_);
691:     ASSERT(state_.filter_call_state_ == 0);
