693: 
694:   // ScopeTrackedObject
695:   OptRef<const StreamInfo::StreamInfo> trackedStream() const override { return streamInfo(); }
696:   void dumpState(std::ostream& os, int indent_level = 0) const override {
697:     const char* spaces = spacesForLevel(indent_level);
698:     os << spaces << "FilterManager " << this << DUMP_MEMBER(state_.has_1xx_headers_)
699:        << DUMP_MEMBER(state_.decoder_filter_chain_complete_)
700:        << DUMP_MEMBER(state_.encoder_filter_chain_complete_)
701:        << DUMP_MEMBER(state_.observed_decode_end_stream_)
702:        << DUMP_MEMBER(state_.observed_encode_end_stream_) << "\n";
703: 
704:     DUMP_DETAILS(filter_manager_callbacks_.requestHeaders());
705:     DUMP_DETAILS(filter_manager_callbacks_.requestTrailers());
706:     DUMP_DETAILS(filter_manager_callbacks_.responseHeaders());
707:     DUMP_DETAILS(filter_manager_callbacks_.responseTrailers());
708:     DUMP_DETAILS(&streamInfo());
709:   }
710: 
711:   void log(const Formatter::Context log_context) {
712:     for (const auto& log_handler : access_log_handlers_) {
713:       log_handler->log(log_context, streamInfo());
714:     }
715:   }
716: 
717:   const AccessLog::InstanceSharedPtrVector& accessLogHandlers() { return access_log_handlers_; }
718: 
719:   void onStreamComplete() {
720:     for (auto filter : filters_) {
721:       filter->onStreamComplete();
722:     }
723:   }
724: 
725:   void destroyFilters() {
726:     state_.destroyed_ = true;
727: 
728:     for (auto filter : filters_) {
729:       filter->onDestroy();
730:     }
731:   }
732: 
733:   /**
734:    * Decodes the provided headers starting at the first filter in the chain.
735:    * @param headers the headers to decode.
736:    * @param end_stream whether the request is header only.
737:    */
738:   void decodeHeaders(RequestHeaderMap& headers, bool end_stream) {
739:     state_.observed_decode_end_stream_ = end_stream;
740:     decodeHeaders(nullptr, headers, end_stream);
741:   }
742: 
743:   /**
744:    * Decodes the provided data starting at the first filter in the chain.
745:    * @param data the data to decode.
746:    * @param end_stream whether this data is the end of the request.
747:    */
748:   void decodeData(Buffer::Instance& data, bool end_stream) {
749:     state_.observed_decode_end_stream_ = end_stream;
750:     decodeData(nullptr, data, end_stream, FilterIterationStartState::CanStartFromCurrent);
751:   }
752: 
753:   /**
754:    * Decodes the provided trailers starting at the first filter in the chain.
755:    * @param trailers the trailers to decode.
756:    */
757:   void decodeTrailers(RequestTrailerMap& trailers) {
758:     state_.observed_decode_end_stream_ = true;
759:     decodeTrailers(nullptr, trailers);
760:   }
761: 
762:   /**
763:    * Decodes the provided metadata starting at the first filter in the chain.
764:    * @param metadata_map the metadata to decode.
765:    */
766:   void decodeMetadata(MetadataMap& metadata_map) { decodeMetadata(nullptr, metadata_map); }
767: 
768:   void disarmRequestTimeout();
769: 
770:   /**
