780:    */
781:   void maybeEndDecode(bool terminal_filter_decoded_end_stream);
782: 
783:   void checkAndCloseStreamIfFullyClosed();
784: 
785:   virtual void sendLocalReply(Code code, absl::string_view body,
786:                               const std::function<void(ResponseHeaderMap& headers)>& modify_headers,
787:                               const absl::optional<Grpc::Status::GrpcStatus> grpc_status,
788:                               absl::string_view details) PURE;
789: 
790:   void resetStream(StreamResetReason reason, absl::string_view transport_failure_reason);
791: 
792:   /**
