801:   /**
802:    * @return uint64_t the current buffer limit.
803:    */
804:   uint64_t bufferLimit() const { return buffer_limit_; }
805: 
806:   /**
807:    * @return bool whether any above high watermark triggers are currently active
808:    */
809:   bool aboveHighWatermark() { return high_watermark_count_ != 0; }
