825:   /**
826:    * Marks local processing as complete.
827:    * TODO(yanvlasov): deprecate and decommission this function.
828:    */
829:   void setLocalComplete() {
830:     state_.observed_encode_end_stream_ = true;
831:     state_.decoder_filter_chain_aborted_ = true;
832:   }
833: 
834:   /**
835:    * Whether the filters have been destroyed.
836:    */
