870:         : created_(created), upgrade_(upgrade) {}
871: 
872:     /**
873:      * @return whether the filter chain was created.
874:      */
875:     bool created() const { return created_; }
876:     /**
877:      * @return whether the upgrade was accepted.
878:      */
879:     bool upgradeAccepted() const { return upgrade_ == UpgradeResult::UpgradeAccepted; }
880:     /**
881:      * @return whether the upgrade was rejected.
882:      */
883:     bool upgradeRejected() const { return upgrade_ == UpgradeResult::UpgradeRejected; }
