890:   /**
891:    * Set up the Encoder/Decoder filter chain.
892:    * @param filter_chain_factory the factory to create the filter chain.
893:    */
894:   CreateChainResult createFilterChain(const FilterChainFactory& filter_chain_factory);
895: 
896:   OptRef<const Network::Connection> connection() const { return connection_; }
897: 
898:   uint64_t streamId() const { return stream_id_; }
899:   Buffer::BufferMemoryAccountSharedPtr account() const { return account_; }
900: 
901:   Buffer::InstancePtr& bufferedRequestData() { return buffered_request_data_; }
902: 
903:   void contextOnContinue(ScopeTrackedObjectStack& tracked_object_stack);
904: 
905:   void onDownstreamReset() { state_.saw_downstream_reset_ = true; }
906:   bool sawDownstreamReset() { return state_.saw_downstream_reset_; }
907: 
908:   virtual bool shouldLoadShed() { return false; };
909: 
910:   void sendGoAwayAndClose(bool graceful = false) {
911:     // Stop filter chain iteration by checking encoder or decoder chain.
912:     if (state_.filter_call_state_ & FilterCallState::IsDecodingMask) {
913:       state_.decoder_filter_chain_aborted_ = true;
914:     } else if (state_.filter_call_state_ & FilterCallState::IsEncodingMask) {
915:       state_.encoder_filter_chain_aborted_ = true;
916:     }
917:     filter_manager_callbacks_.sendGoAwayAndClose(graceful);
918:   }
