920: protected:
921:   struct State {
922:     State() = default;
923:     uint32_t filter_call_state_{0};
924: 
925:     // Set after decoder filter chain has completed iteration. Prevents further calls to decoder
926:     // filters. This flag is used to determine stream completion when the independent half-close is
927:     // enabled.
928:     bool decoder_filter_chain_complete_{};
929: 
930:     // Set after encoder filter chain has completed iteration. Prevents further calls to encoder
931:     // filters. This flag is used to determine stream completion when the independent half-close is
932:     // enabled.
933:     bool encoder_filter_chain_complete_{};
934: 
935:     // Set `true` when the filter manager observes end stream on the decoder path (from downstream
936:     // client) before iteration of the decoder filter chain begins. This flag is used for setting
937:     // end_stream value when resuming decoder filter chain iteration.
938:     bool observed_decode_end_stream_{};
939:     // Set `true` when the filter manager observes end stream on the encoder path (from upstream
940:     // server or Envoy's local reply) before iteration of the encoder filter chain begins. This flag
941:     // is used for setting end_stream value when resuming encoder filter chain iteration.
942:     bool observed_encode_end_stream_{};
943: 
944:     // By default, we will assume there are no 1xx. If encode1xxHeaders
945:     // is ever called, this is set to true so commonContinue resumes processing the 1xx.
946:     bool has_1xx_headers_{};
947:     // These two are latched on initial header read, to determine if the original headers
948:     // constituted a HEAD or gRPC request, respectively.
949:     bool is_head_request_{};
950:     bool is_grpc_request_{};
951:     // Tracks if headers other than 100-Continue have been encoded to the codec.
952:     bool non_100_response_headers_encoded_{};
953:     // True under the stack of onLocalReply, false otherwise.
954:     bool under_on_local_reply_{};
955:     // True when the filter chain iteration was aborted with local reply.
956:     bool decoder_filter_chain_aborted_{};
957:     bool encoder_filter_chain_aborted_{};
958:     bool saw_downstream_reset_{};
959:     // True when the stream was recreated.
960:     bool recreated_stream_{};
961: 
962:     // The following 3 members are booleans rather than part of the space-saving bitfield as they
963:     // are passed as arguments to functions expecting bools. Extend State using the bitfield
964:     // where possible.
965:     bool encoder_filters_streaming_{true};
966:     bool decoder_filters_streaming_{true};
967:     bool destroyed_{false};
968: 
969:     // Result of filter chain creation.
970:     CreateChainResult create_chain_result_;
