343:   // Upstream::LoadBalancerContext
344:   absl::optional<uint64_t> computeHashKey() override {
345:     if (route_entry_ && downstream_headers_) {
346:       // Use cluster-level hash policy if available (most specific wins).
347:       // If no cluster-level policy is configured, fall back to route-level policy.
348:       const Http::HashPolicy* hash_policy =
349:           cluster_ != nullptr ? cluster_->httpProtocolOptions().hashPolicy() : nullptr;
350:       if (hash_policy == nullptr) {
351:         hash_policy = route_entry_->hashPolicy();
352:       }
353: 
354:       if (hash_policy) {
355:         return hash_policy->generateHash(
356:             *downstream_headers_, callbacks_->streamInfo(),
357:             [this](absl::string_view key, absl::string_view path, std::chrono::seconds max_age,
358:                    absl::Span<const Http::CookieAttribute> attributes) -> std::string {
359:               return addDownstreamSetCookie(key, path, max_age, attributes);
360:             });
361:       }
362:     }
363:     return {};
364:   }
365:   const Router::MetadataMatchCriteria* metadataMatchCriteria() override {
366:     if (!route_entry_) {
367:       return nullptr;
368:     }
369: 
370:     // Have we been called before? If so, there's no need to recompute because
371:     // by the time this method is called for the first time, route_entry_ should
372:     // not change anymore.
373:     if (metadata_match_ != nullptr) {
374:       return metadata_match_.get();
375:     }
376: 
377:     OptRef<const Protobuf::Struct> connection_metadata;
378:     const auto* downstream_conn = downstreamConnection();
379:     if (downstream_conn != nullptr) {
380:       const auto& connection_fm = downstream_conn->streamInfo().dynamicMetadata().filter_metadata();
381:       if (const auto it = connection_fm.find(Envoy::Config::MetadataFilters::get().ENVOY_LB);
382:           it != connection_fm.end()) {
383:         connection_metadata = makeOptRef<const Protobuf::Struct>(it->second);
384:       }
385:     }
386: 
387:     OptRef<const Protobuf::Struct> request_metadata;
388:     const auto& request_fm = callbacks_->streamInfo().dynamicMetadata().filter_metadata();
389:     if (const auto it = request_fm.find(Envoy::Config::MetadataFilters::get().ENVOY_LB);
390:         it != request_fm.end()) {
391:       request_metadata = makeOptRef<const Protobuf::Struct>(it->second);
392:     }
393: 
394:     // The precedence is: request metadata > connection metadata > route criteria.
395:     // We start with the route's criteria and sequentially merge others on top.
396:     const auto* base_criteria = route_entry_->metadataMatchCriteria();
397:     Router::MetadataMatchCriteriaConstPtr merged_criteria;
398: 
399:     const auto* current_base = base_criteria;
400: 
401:     // Merge connection metadata, if it exists.
402:     if (connection_metadata) {
403:       merged_criteria =
404:           current_base ? current_base->mergeMatchCriteria(*connection_metadata)
405:                        : std::make_unique<Router::MetadataMatchCriteriaImpl>(*connection_metadata);
406:       current_base = merged_criteria.get();
407:     }
408: 
409:     // Merge request metadata, if it exists.
410:     if (request_metadata) {
411:       merged_criteria =
412:           current_base ? current_base->mergeMatchCriteria(*request_metadata)
413:                        : std::make_unique<Router::MetadataMatchCriteriaImpl>(*request_metadata);
414:     }
415: 
416:     // If merged_criteria is null, no merges occurred. Return the original base criteria.
417:     if (!merged_criteria) {
418:       return base_criteria;
419:     }
420: 
421:     // Otherwise, cache the newly created criteria and return it.
422:     metadata_match_ = std::move(merged_criteria);
423:     return metadata_match_.get();
424:   }
