482:   /**
483:    * Set a computed cookie to be sent with the downstream headers.
484:    * @param key supplies the size of the cookie
485:    * @param max_age the lifetime of the cookie
486:    * @param  path the path of the cookie, or ""
487:    * @return std::string the value of the new cookie
488:    */
489:   std::string addDownstreamSetCookie(absl::string_view key, absl::string_view path,
490:                                      std::chrono::seconds max_age,
491:                                      absl::Span<const Http::CookieAttribute> attributes) {
492:     // The cookie value should be the same per connection so that if multiple
493:     // streams race on the same path, they all receive the same cookie.
494:     // Since the downstream port is part of the hashed value, multiple HTTP1
495:     // connections can receive different cookies if they race on requests.
496:     std::string value;
497:     const Network::Connection* conn = downstreamConnection();
498:     // Need to check for null conn if this is ever used by Http::AsyncClient in the future.
499:     value = conn->connectionInfoProvider().remoteAddress()->asString() +
500:             conn->connectionInfoProvider().localAddress()->asString();
501: 
502:     const std::string cookie_value = Hex::uint64ToHex(HashUtil::xxHash64(value));
503:     downstream_set_cookies_.emplace_back(
504:         Http::Utility::makeSetCookieValue(key, cookie_value, path, max_age, true, attributes));
505:     return cookie_value;
506:   }
