255:     ClusterInfoMaps clusters_maps;
256:     for (const auto& cluster : active_clusters_) {
257:       clusters_maps.active_clusters_.emplace(cluster.first, *cluster.second->cluster_);
258:       if (cluster.second->cluster_->info()->addedViaApi()) {
259:         ++clusters_maps.added_via_api_clusters_num_;
260:       }
261:     }
262:     for (const auto& cluster : warming_clusters_) {
263:       clusters_maps.warming_clusters_.emplace(cluster.first, *cluster.second->cluster_);
264:       if (cluster.second->cluster_->info()->addedViaApi()) {
265:         ++clusters_maps.added_via_api_clusters_num_;
266:       }
267:     }
268:     // The number of clusters that were added via API must be at most the number
269:     // of active clusters + number of warming clusters.
270:     ASSERT(clusters_maps.added_via_api_clusters_num_ <=
271:            clusters_maps.active_clusters_.size() + clusters_maps.warming_clusters_.size());
