125: // Express percentage as [0, TimeoutPrecisionFactor] because stats do not accept floating point
126: // values, and getting multiple significant figures on the histogram would be nice.
127: uint64_t FilterUtility::percentageOfTimeout(const std::chrono::milliseconds response_time,
128:                                             const std::chrono::milliseconds timeout) {
129:   // Timeouts of 0 are considered infinite. Any portion of an infinite timeout used is still
130:   // none of it.
131:   if (timeout.count() == 0) {
132:     return 0;
133:   }
134: 
135:   return static_cast<uint64_t>(response_time.count() * TimeoutPrecisionFactor / timeout.count());
136: }
