441:   downstream_headers_ = &headers;
442: 
443:   // Initialize the `modify_headers_` function that will be used to modify the response headers for
444:   // all upstream responses or local responses.
445:   modify_headers_ = [this](Http::ResponseHeaderMap& headers) {
446:     if (route_entry_ == nullptr) {
