72: template <class FilterCtx, class NeutralNamedHttpFilterFactory>
73: class FilterChainHelper : Logger::Loggable<Logger::Id::config> {
74: public:
75:   using FilterFactoriesList = FilterChainUtility::FilterFactoriesList;
76:   using FilterConfigProviderManager =
77:       Filter::FilterConfigProviderManager<Filter::HttpFilterFactoryCb, FilterCtx>;
78: 
79:   FilterChainHelper(FilterConfigProviderManager& filter_config_provider_manager,
80:                     Server::Configuration::ServerFactoryContext& server_context,
81:                     Upstream::ClusterManager& cluster_manager, FilterCtx& factory_context,
82:                     const std::string& stats_prefix)
83:       : filter_config_provider_manager_(filter_config_provider_manager),
84:         server_context_(server_context), cluster_manager_(cluster_manager),
85:         factory_context_(factory_context), stats_prefix_(stats_prefix) {}
86: 
87:   // Process the filters in this filter chain.
88:   absl::Status processFilters(const FiltersList& filters, const std::string& prefix,
89:                               const std::string& filter_chain_type,
90:                               FilterFactoriesList& filter_factories) {
91: 
92:     DependencyManager dependency_manager;
93:     filter_factories.reserve(filters.size());
94:     for (int i = 0; i < filters.size(); i++) {
95:       absl::Status status =
96:           processFilter(filters[i], i, prefix, filter_chain_type, i == filters.size() - 1,
97:                         filter_factories, dependency_manager);
98:       if (!status.ok()) {
99:         return status;
100:       }
101:     }
102:     // TODO(auni53): Validate encode dependencies too.
103:     return dependency_manager.validDecodeDependencies();
104:   }
105: 
106: private:
107:   absl::Status
108:   processFilter(const envoy::extensions::filters::network::http_connection_manager::v3::HttpFilter&
109:                     proto_config,
110:                 int i, const std::string& prefix, const std::string& filter_chain_type,
111:                 bool last_filter_in_current_config, FilterFactoriesList& filter_factories,
112:                 DependencyManager& dependency_manager) {
113:     ENVOY_LOG(debug, "    {} filter #{}", prefix, i);
114: 
115:     const bool disabled_by_default = proto_config.disabled();
116: 
117:     // Ensure the terminal filter will not be disabled by default. Because the terminal filter must
118:     // be the last filter in the chain (ensured by 'validateTerminalFilters') and terminal flag of
119:     // dynamic filter could not determined and may changed at runtime, so we check the last filter
120:     // flag here as alternative.
121:     if (last_filter_in_current_config && disabled_by_default) {
122:       return absl::InvalidArgumentError(fmt::format(
123:           "Error: the last (terminal) filter ({}) in the chain cannot be disabled by default.",
124:           proto_config.name()));
125:     }
126: 
127:     if (proto_config.config_type_case() ==
128:         envoy::extensions::filters::network::http_connection_manager::v3::HttpFilter::
129:             ConfigTypeCase::kConfigDiscovery) {
130:       return processDynamicFilterConfig(proto_config.name(), proto_config.config_discovery(),
131:                                         filter_factories, filter_chain_type,
132:                                         last_filter_in_current_config, disabled_by_default);
133:     }
134: 
135:     // Now see if there is a factory that will accept the config.
136:     auto* factory = Config::Utility::getAndCheckFactory<NeutralNamedHttpFilterFactory>(
137:         proto_config, proto_config.is_optional());
138:     // null pointer returned only when the filter is optional, then skip all the processes.
139:     if (factory == nullptr) {
140:       ENVOY_LOG(warn, "Didn't find a registered factory for the optional http filter {}",
141:                 proto_config.name());
142:       return absl::OkStatus();
143:     }
144:     ProtobufTypes::MessagePtr message = Config::Utility::translateToFactoryConfig(
145:         proto_config, server_context_.messageValidationVisitor(), *factory);
146:     absl::StatusOr<Http::FilterFactoryCb> callback_or_error =
147:         factory->createFilterFactoryFromProto(*message, stats_prefix_, factory_context_);
148:     if (!callback_or_error.status().ok()) {
149:       return callback_or_error.status();
150:     }
151:     dependency_manager.registerFilter(factory->name(), *factory->dependencies());
152:     const bool is_terminal = factory->isTerminalFilterByProto(*message, server_context_);
153:     RETURN_IF_NOT_OK(Config::Utility::validateTerminalFilters(proto_config.name(), factory->name(),
154:                                                               filter_chain_type, is_terminal,
155:                                                               last_filter_in_current_config));
156:     auto filter_config_provider = filter_config_provider_manager_.createStaticFilterConfigProvider(
157:         callback_or_error.value(), proto_config.name());
158: #ifdef ENVOY_ENABLE_YAML
159:     ENVOY_LOG(debug, "      name: {}", filter_config_provider->name());
160:     ENVOY_LOG(debug, "    config: {}",
161:               MessageUtil::getJsonStringFromMessageOrError(
162:                   static_cast<const Protobuf::Message&>(proto_config.typed_config())));
163: #endif
164:     filter_factories.push_back({std::move(filter_config_provider), disabled_by_default});
165:     return absl::OkStatus();
166:   }
167: 
168:   absl::Status
169:   processDynamicFilterConfig(const std::string& name,
170:                              const envoy::config::core::v3::ExtensionConfigSource& config_discovery,
171:                              FilterFactoriesList& filter_factories,
172:                              const std::string& filter_chain_type,
173:                              bool last_filter_in_current_config, bool disabled_by_default) {
174:     ENVOY_LOG(debug, "      dynamic filter name: {}", name);
175:     if (config_discovery.apply_default_config_without_warming() &&
176:         !config_discovery.has_default_config()) {
177:       return absl::InvalidArgumentError(fmt::format(
178:           "Error: filter config {} applied without warming but has no default config.", name));
179:     }
180:     for (const auto& type_url : config_discovery.type_urls()) {
181:       auto factory_type_url = TypeUtil::typeUrlToDescriptorFullName(type_url);
182:       auto* factory = Registry::FactoryRegistry<NeutralNamedHttpFilterFactory>::getFactoryByType(
183:           factory_type_url);
184:       if (factory == nullptr) {
185:         return absl::InvalidArgumentError(
186:             fmt::format("Error: no factory found for a required type URL {}.", factory_type_url));
187:       }
188:     }
189: 
190:     auto filter_config_provider = filter_config_provider_manager_.createDynamicFilterConfigProvider(
191:         config_discovery, name, server_context_, factory_context_, cluster_manager_,
192:         last_filter_in_current_config, filter_chain_type, nullptr);
193:     filter_factories.push_back({std::move(filter_config_provider), disabled_by_default});
194:     return absl::OkStatus();
195:   }
196: 
197:   FilterConfigProviderManager& filter_config_provider_manager_;
198:   Server::Configuration::ServerFactoryContext& server_context_;
199:   Upstream::ClusterManager& cluster_manager_;
200:   FilterCtx& factory_context_;
201:   const std::string& stats_prefix_;
202: };
203: 
204: } // namespace Http
205: } // namespace Envoy
